const sourceSystem = typeof $json.sourceSystem === 'string' ? $json.sourceSystem : 'competitor_feed';
const records = Array.isArray($json.records) ? $json.records : [];
const blocked = ['google_maps'];
if (blocked.includes(sourceSystem)) {
  throw new Error('Blocked sourceSystem. Review ToS before enabling this feed.');
}
const leads = records.map((row, index) => ({
  sourceRecordId: String(row.sourceRecordId ?? `${sourceSystem}-${index}`),
  sourceUrl: row.sourceUrl ?? null,
  category: String(row.category ?? row.vertical ?? ''),
  location: {
    latitude: Number(row.latitude ?? row.lat),
    longitude: Number(row.longitude ?? row.lon),
  },
  normalizedDetails: row.normalizedDetails ?? {
    name: row.name ?? null,
    brand: row.brand ?? null,
  },
  rawPayload: row,
  evidenceUrls: Array.isArray(row.evidenceUrls) ? row.evidenceUrls : [],
  freshnessAt: row.freshnessAt ?? new Date().toISOString(),
  priority: row.priority ?? 'medium',
}));
return [{ json: { runKey: `${sourceSystem}-${Date.now()}`, workflowName: 'adl-competitor-leads', sourceSystem, triggerType: 'webhook', startedAt: new Date().toISOString(), completedAt: new Date().toISOString(), leads } }];
